+				isIntersecting: entry.isIntersecting
+			};
+			if (
+				previous === null ||
+				previous.isIntersecting !== current.isIntersecting ||
+				this.#thresholdIndex(previous.ratio) !== this.#thresholdIndex(current.ratio)
+			) {
+				this.#records.push(entry);
+			}
+			this.#observations.set(target, current);
+		}
