+			: new DOMRect(0, 0, this.#getViewportWidth(), this.#getViewportHeight());
+		const top = this.#resolveMargin(this.#rootMarginValues[0], rootRect.height);
+		const right = this.#resolveMargin(this.#rootMarginValues[1], rootRect.width);
+		const bottom = this.#resolveMargin(this.#rootMarginValues[2], rootRect.height);
+		const left = this.#resolveMargin(this.#rootMarginValues[3], rootRect.width);
+		return new DOMRect(
+			rootRect.left - left,
+			rootRect.top - top,
+			rootRect.width + left + right,
+			rootRect.height + top + bottom
+		);
+	}
