+	/** Creates an entry from the target and root rectangles. */
+	#createEntry(target: Element, rootBounds: DOMRect): IntersectionObserverEntry {
+		const targetRect = target.getBoundingClientRect();
+		const intersectionLeft = Math.max(targetRect.left, rootBounds.left);
+		const intersectionTop = Math.max(targetRect.top, rootBounds.top);
+		const intersectionRight = Math.min(targetRect.right, rootBounds.right);
+		const intersectionBottom = Math.min(targetRect.bottom, rootBounds.bottom);
+		const intersects = intersectionRight >= intersectionLeft && intersectionBottom >= intersectionTop;
+		const intersectionRect = new DOMRect(
+			intersectionLeft,
+			intersectionTop,
+			Math.max(0, intersectionRight - intersectionLeft),
+			Math.max(0, intersectionBottom - intersectionTop)
+		);
+		const targetArea = Math.max(0, targetRect.width) * Math.max(0, targetRect.height);
+		const intersectionArea = intersectionRect.width * intersectionRect.height;
+		const contained =
+			targetRect.left >= rootBounds.left &&
+			targetRect.right <= rootBounds.right &&
+			targetRect.top >= rootBounds.top &&
+			targetRect.bottom <= rootBounds.bottom;
+		const ratio = targetArea === 0 ? (contained ? 1 : 0) : intersectionArea / targetArea;
+
+		return new IntersectionObserverEntry({
+			boundingClientRect: targetRect,
+			intersectionRatio: ratio,
+			intersectionRect,
+			isIntersecting: intersects && (targetArea === 0 ? contained : intersectionArea > 0),
+			rootBounds,
+			target,
+			time: performance.now()
