+	#getViewportWidth(): number {
+		for (const window of this.#observedWindows) {
+			return window.innerWidth;
+		}
+		return 0;
+	}
+
+	#getViewportHeight(): number {
+		for (const window of this.#observedWindows) {
+			return window.innerHeight;
+		}
+		return 0;
+	}
+
+	#parseRootMargin(rootMargin: string | undefined): IRootMarginValue[] {
+		const values = (rootMargin ?? '0px').trim().split(/\\s+/);
+		if (values.length < 1 || values.length > 4 || (values.length === 1 && values[0] === '')) {
+			throw new DOMException('Invalid rootMargin.', DOMExceptionNameEnum.syntaxError);
+		}
+		const parsed = values.map((value) => {
+			const match = /^([+-]?(?:\\d+(?:\\.\\d*)?|\\.\\d+))(px|%)$/.exec(value);
+			if (!match || !Number.isFinite(Number(match[1]))) {
+				throw new DOMException('Invalid rootMargin.', DOMExceptionNameEnum.syntaxError);
+			}
+			return {
+				value: Number(match[1]),
+				unit: match[2] as 'px' | '%',
+				serialized: `${Number(match[1])}${match[2]}`
+			};
+		});
+		return [parsed[0], parsed[1] ?? parsed[0], parsed[2] ?? parsed[0], parsed[3] ?? parsed[1] ?? parsed[0]];
+	}
+
+	#parseThresholds(threshold: number | number[] | undefined): number[] {
+		const values = threshold === undefined ? [0] : Array.isArray(threshold) ? threshold : [threshold];
+		if (values.some((value) => typeof value !== 'number' || !Number.isFinite(value) || value < 0 || value > 1)) {
+			throw new RangeError('IntersectionObserver threshold must be a number between 0 and 1.');
+		}
+		return [...new Set(values)].sort((a, b) => a - b);
+	}
